import{_ as o,o as e,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G03: 核心員工流動率審計 - 經營審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6442_光聖/20260504/G03_核心員工流動率審計.md","filePath":"審計報告庫/經營審計/6442_光聖/20260504/G03_核心員工流動率審計.md"}'),i={name:"審計報告庫/經營審計/6442_光聖/20260504/G03_核心員工流動率審計.md"};function n(l,a,s,h,d,_){return e(),t("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的經營洞見。</p><h1 id="g03-核心員工流動率審計-經營審計專家報告" tabindex="-1">G03: 核心員工流動率審計 - 經營審計專家報告 <a class="header-anchor" href="#g03-核心員工流動率審計-經營審計專家報告" aria-label="Permalink to &quot;G03: 核心員工流動率審計 - 經營審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>核心技術或研發團隊的流動率為何？公司如何留住優秀人才？是否有關鍵人才流向競爭對手的跡象？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>非主管員工約390-400人，總員工逾1,100人。平均薪資2024年103.9萬（YoY+54%），RSU三年分段既得為留任核心。無重大人才流向競爭對手。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A- (良)</strong>：員工薪酬競爭力顯著提升。非主管員工2023年402人/67.3萬→2024年390人/103.9萬（薪資暴增54.4%）。2025年R&amp;D費用NT$9,362萬。公司採精兵政策，營收+64%但員工人數僅微增。研發費用佔營收0.89%以技術型公司標準偏低。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>平均薪資2023年67.3萬→2024年103.9萬（+54.4%）優於同業。RSU發行400仟股（2024）擬再發1,000+500仟股（2025），採3年分段既得（30%-30%-40%）捆綁核心員工在AI黃金擴張期穩定留任。員工酬勞強制不低於10%分配基層。</p><p>2025年R&amp;D費用NT$9,362萬（佔營收0.89%），全球專利&gt;180項，研發據點台灣+捷克。技術長徐茂傑2020年因病辭職後無重大研發主管異動。R&amp;D費用率0.89%低於同業（波若威3-5%/華星光4-6%），但核心競爭力來自技術收購整合而非自研，有其合理性。矽光子/CPO轉型需更高自研投入。</p><p>公開資訊未檢出核心團隊大量流向競爭對手。104徵才為擴張性（製程/自動化工程師）非離職遞補。員工評價管理層缺乏同情心為台廠通病。風險在人才通膨與海外據點管理人才短缺。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>研發投入不足警訊</strong>：R&amp;D費用率0.89%偏低，在矽光子/CPO技術轉型的關鍵路口，若自研能力無法跟上競爭對手（英特磊、華星光等積極投入者），可能錯失下一代資料中心架構商機。</li><li><strong>薪資通膨壓力</strong>：平均薪資1年暴增54%至103.9萬，若營收增速放緩（2026年前2月YoY已現波動），薪資剛性將壓縮獲利空間。2026年2月營收7.38億（YoY+44%仍強勁），但高基期效應下薪資成長是否可持續存疑。</li><li><strong>中低階管理評價挑戰</strong>：員工對管理層評價分歧，若組織擴張快速（員工人數需從1,100增至因應產能擴充所需），管理品質稀釋風險升高。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>人均產值大幅拉升</strong>：2024-2025年員工人數增長有限但營收倍增至105.3億，人均營收估超NT$955萬，顯示AI訂單的規模效應顯著，屬「高價值、低人力密集」的優質獲利模式。</li><li><strong>RSU長效鎖籌</strong>：限制員工權利新股機制完善，3年分段既得有效延緩核心人才離職誘因，在AI紅利爆發期提供競爭對手難以複製的留任優勢。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>web_search</strong>：Goodinfo員工薪資統計（非主管職員工人數/平均薪資）、公司徵才資訊、法人說明會資料</li><li><strong>FinMind</strong>：TaiwanStockMonthRevenue (2023/05-2026/03)</li><li><strong>PDF分析</strong>：2025年合併財報（員工福利費用NT$15.7億、RSU條件、員工酬勞政策）</li><li><strong>原始數據</strong>：stock_id=6442, employee data from Goodinfo/company reports</li></ul>',19)])])}const m=o(i,[["render",n]]);export{p as __pageData,m as default};
